// frontend/src/pages/UploadResume.js
import React, { useState } from 'react';
import axios from 'axios';

const UploadResume = () => {
  const [resumeText, setResumeText] = useState('');
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');
  const token = localStorage.getItem('token');

  const handleUpload = async () => {
    if (!resumeText) {
      setMessage('Please paste your resume text');
      setMessageType('error');
      return;
    }

    setUploading(true);
    setMessage('');
    
    try {
      // Match your Application model structure
      const applicationData = {
        jobTitle: "Resume Upload",
        companyName: "Self",
        status: "Draft",
        resumeText: resumeText,
        jobDescription: "",  // Optional
        notes: ""  // Optional
      };
      
      console.log("Sending data:", applicationData);
      console.log("Token:", token);
      
      const response = await axios.post(
        'http://localhost:5000/api/applications',
        applicationData,
        { 
          headers: { 
            'x-auth-token': token,
            'Content-Type': 'application/json'
          } 
        }
      );
      
      console.log("Response:", response.data);
      
      setMessage('✅ Resume uploaded successfully! AI will now analyze your profile.');
      setMessageType('success');
      
      // Also save to localStorage for AI to access
      localStorage.setItem('userResume', resumeText);
      
      // Clear success message after 3 seconds
      setTimeout(() => setMessage(''), 3000);
      
    } catch (error) {
      console.error('Upload error:', error);
      console.error('Error response:', error.response?.data);
      
      let errorMsg = '❌ Error uploading resume. ';
      
      if (error.response?.data?.error) {
        errorMsg += error.response.data.error;
      } else if (error.response?.status === 401) {
        errorMsg += 'Please login again.';
      } else if (error.response?.status === 500) {
        errorMsg += 'Server error. Check backend console.';
      } else {
        errorMsg += 'Please check if backend is running on port 5000';
      }
      
      setMessage(errorMsg);
      setMessageType('error');
    }
    setUploading(false);
  };

  return (
    <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}>
      <h1>📄 Upload Your Resume</h1>
      
      {/* Backend Status Check */}
      <div style={{
        padding: '10px',
        borderRadius: '5px',
        marginBottom: '20px',
        background: '#e8f4f8',
        color: '#0c5460'
      }}>
        ℹ️ Backend running on port 5000
      </div>
      
      <div style={{ marginBottom: '20px' }}>
        <label style={{ display: 'block', marginBottom: '10px', fontWeight: 'bold' }}>
          Paste your resume text here:
        </label>
        <textarea
          rows={15}
          value={resumeText}
          onChange={(e) => setResumeText(e.target.value)}
          placeholder="Paste your resume content here..."
          style={{
            width: '100%',
            padding: '10px',
            border: '1px solid #ddd',
            borderRadius: '5px',
            fontFamily: 'monospace',
            fontSize: '14px'
          }}
        />
      </div>

      <button
        onClick={handleUpload}
        disabled={uploading}
        style={{
          padding: '10px 20px',
          background: '#007bff',
          color: 'white',
          border: 'none',
          borderRadius: '5px',
          cursor: uploading ? 'not-allowed' : 'pointer',
          opacity: uploading ? 0.6 : 1
        }}
      >
        {uploading ? 'Uploading...' : '📤 Upload Resume'}
      </button>

      {message && (
        <div style={{
          marginTop: '20px',
          padding: '10px',
          background: messageType === 'success' ? '#d4edda' : '#f8d7da',
          color: messageType === 'success' ? '#155724' : '#721c24',
          borderRadius: '5px',
          border: `1px solid ${messageType === 'success' ? '#c3e6cb' : '#f5c6cb'}`
        }}>
          {message}
        </div>
      )}

      {/* Sample Resume Section */}
      <div style={{ marginTop: '30px', padding: '15px', background: '#f5f5f5', borderRadius: '10px' }}>
        <h3>📝 Sample Resume (Click to use)</h3>
        <pre style={{ whiteSpace: 'pre-wrap', fontSize: '12px', background: 'white', padding: '10px', borderRadius: '5px' }}>
{`John Doe
Software Engineer
Email: john.doe@example.com

SUMMARY
Experienced Python Developer with 5+ years of experience in full-stack development.
Strong background in building scalable web applications and RESTful APIs.

TECHNICAL SKILLS
- Programming Languages: Python, JavaScript, Java, SQL
- Frameworks: Django, Flask, React, Node.js
- Databases: PostgreSQL, MongoDB, MySQL
- Cloud & DevOps: AWS (EC2, S3, Lambda), Docker, Git, Jenkins

WORK EXPERIENCE
Senior Software Engineer | Tech Corp | 2020-Present
- Developed REST APIs using Django and Django REST Framework
- Built React frontend components
- Implemented CI/CD pipeline using Jenkins

EDUCATION
Bachelor of Technology in Computer Science
University Name | 2014-2018`}
        </pre>
        <button
          onClick={() => setResumeText(`John Doe
Software Engineer

SUMMARY
Experienced Python Developer with 5+ years of experience in full-stack development.
Strong background in building scalable web applications and RESTful APIs.

TECHNICAL SKILLS
- Programming Languages: Python, JavaScript, Java, SQL
- Frameworks: Django, Flask, React, Node.js
- Databases: PostgreSQL, MongoDB, MySQL
- Cloud & DevOps: AWS (EC2, S3, Lambda), Docker, Git, Jenkins

WORK EXPERIENCE
Senior Software Engineer | Tech Corp | 2020-Present
- Developed REST APIs using Django and Django REST Framework
- Built React frontend components
- Implemented CI/CD pipeline using Jenkins

EDUCATION
Bachelor of Technology in Computer Science
University Name | 2014-2018`)}
          style={{
            marginTop: '10px',
            padding: '8px 16px',
            background: '#28a745',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer'
          }}
        >
          📋 Use This Sample Resume
        </button>
      </div>

      {/* Instructions */}
      <div style={{ marginTop: '20px', padding: '15px', background: '#e8f4f8', borderRadius: '10px' }}>
        <h4>📌 After Upload:</h4>
        <ol style={{ marginLeft: '20px' }}>
          <li>Go to <strong>Dashboard</strong> to see AI job recommendations</li>
          <li>Go to <strong>AI Dashboard</strong> to see your career path</li>
          <li>Go to <strong>Job Matcher</strong> to compare with any job description</li>
        </ol>
      </div>
    </div>
  );
};

export default UploadResume;
